$$, $$1f6a22b8501f78c3cd561daf508b82d9533e4e8604df1a904d64b3f373249ce3$$, $${"A": "6e95517d45453ee00b5f5b1e4e5b083ba2ea858078eb83f2f3fa104e265b267b", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "f03aa5ae762cea4816e608b04aba9d8c4d520d95ad52572c7d24b9f15817c0b7"}$$::jsonb, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$, 307, $$2026-05-10T04:04:17.793201+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0607384BP$$, 2027, $$This program element (PE) resources Operational System Development across the Understand, Protect, and Mitigate portfolios. Chemical and Biological Defense
Program (CBDP) investments provide an integrated, layered capability to enable Department of War (DoW) missions in a chemical and biological environment, ranging
from combat operations to domestic incident prevention and response. The Projects in this PE support the upgrade of systems that have been fielded or have received
approval for full-rate production in order to maintain Joint Force readiness.

 Individual Projects include:

 - Understand (UN7): Modernization and ongoing engineering of software and information systems. Continued development and testing of CB sensor equipment to
 ensure interoperability with emerging information technology and reduce size, weight, and power requirements, thereby easing logistical burdens. Refresh fielded
 medical diagnostic systems and capabilities, such as assays, to strengthen defenses against biological warfare agents. Upgrade medical nerve agent treatment
 systems to enhance defenses against chemical warfare threats facing U.S. Forces.

 - Protect (PT7): Efforts to refresh technology of fielded individual and protective equipment that enables the Joint Force to operate in a contaminated chemical and
 biological (CB) environment with little or no degradation of performance. Technology refresh efforts for fielded collective protection systems that are smaller, lighter, less
 costly to produce and maintain, and more logistically supportable, enabling mission accomplishment in spaces safe from the effects of CB contamination.

 - Mitigate (MT7): Technology refresh of fielded Contamination Mitigation systems that will remove and/or detoxify contaminated material without damaging combat
 equipment, personnel, or the environment.

 The projects in this PE support operational systems development necessary to maintain operational effectiveness and are, therefore, correctly placed in Budget Activity
 7.
